"""Импульсный шум."""from __future__ import annotationsimport numpy as npfrom ..core.types import Signalfrom .base import BaseNoiseclass ImpulsiveNoise(BaseNoise):    name = "Импульсный шум"    description = ("Редкие знакопеременные импульсы, Бернулли-маска. "                   "Приводится к целевому SNR.")    params_schema = {        "target_snr_db": {"type": "float", "default": 10.0,                          "min": -40.0, "max": 80.0,                          "label": "Целевой SNR", "units": "дБ"},        "probability":   {"type": "float", "default": 0.02,                          "min": 1.0e-6, "max": 0.5,                          "label": "Вероятность импульса"},        "seed":          {"type": "int", "default": 42,                          "min": 0, "max": 2_147_483_647,                          "label": "Seed ГПСЧ"},    }    def _generate_raw(self, clean: Signal, p: dict,                      rng: np.random.Generator) -> np.ndarray:        n = clean.x.size        prob = float(p["probability"])        mask = rng.random(size=n) < prob        if not np.any(mask):            raise ValueError(                f"ImpulsiveNoise: ни одного импульса при probability={prob} и "                f"N={n}. Увеличьте probability или длину сигнала."            )        signs = np.where(rng.random(size=n) < 0.5, -1.0, 1.0)        raw = np.zeros(n, dtype=np.float64)        raw[mask] = signs[mask]        return raw